/**
 * Starts coroutine in a non-cancellable (atomic) way.
 *
 * This method exists to correctly handle failures of the [CoroutineDispatcher] during coroutine start.
 */
internal fun <R, T> (suspend (R) -> T).startCoroutineAtomic(receiver: R, completion: Continuation<T>): Unit =
