import kotlinx.coroutines.testing.runTest
import kotlin.coroutines.CoroutineContext
import kotlin.test.Test
import kotlin.test.assertFailsWith
import kotlin.time.Duration.Companion.seconds

class FlowOnDispatcherFailureTest : TestBase() {

    @Test
    fun testFlowOnDispatcherFailureDoesNotHang() = runTest {
        val failing = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw TestException()
            }
        }

        val flow = flowOf(1, 2, 3).flowOn(failing)

        assertFailsWith<TestException> {
            withTimeout(1.seconds) {
                flow.collect { /* no-op */ }
            }
        }
    }
}
